mapper.select:
select user_id, available_balance, frozen_balance, version, update_time
from reward_account
where user_id = #{userId, jdbcType=BINARY}

mapper.update:
update reward_account
set frozen_balance = frozen_balance - #{amount},
    version = version + 1,
    update_time = current_timestamp
where user_id = #{userId, jdbcType=BINARY}
  and frozen_balance >= #{amount}
